# Latte, capuchino, saborizados, guatemalteco, moca, chocolate, té chai caliente
def _latte_cap(bebida, oz, leche, expreso, syrup=None):
    items = []
    base = f"{bebida} de {oz} Oz."
    if syrup:
        medida = f"lleva {leche} de leche, {syrup} de syrup y {expreso} de expreso"
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-medida", "pregunta": f"¿Cuánto es la medida correcta para un {bebida} de {oz} Oz.?", "respuesta": medida})
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-leche", "pregunta": f"¿Cuántas Oz. de leche lleva un {bebida} de {oz} Oz.?", "respuesta": leche})
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-syrup", "pregunta": f"¿Cuántas Oz. de syrup lleva un {bebida} de {oz} Oz.?", "respuesta": syrup})
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-expreso", "pregunta": f"¿Cuántas Oz. de expreso lleva un {bebida} de {oz} Oz.?", "respuesta": expreso})
    else:
        medida = f"lleva {leche} de leche y {expreso} de expreso"
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-medida", "pregunta": f"¿Cuánto es la medida correcta para un {bebida} de {oz} Oz.?", "respuesta": medida})
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-leche", "pregunta": f"¿Cuántas Oz. de leche lleva un {bebida} de {oz} Oz.?", "respuesta": leche})
        items.append({"id": f"{bebida.replace(' ', '-')}-{oz}-expreso", "pregunta": f"¿Cuántas Oz. de expreso lleva un {bebida} de {oz} Oz.?", "respuesta": expreso})
    return items

for oz, leche, exp in [(8, "6 Oz.", "1 Oz."), (12, "8 Oz.", "1.5 Oz."), (16, "10 Oz.", "2 Oz.")]:
    MEDIDAS_RECETAS.extend(_latte_cap("latte", oz, leche, exp))

